# Problem: Implement a simplified Django-style Class-Based View (CBV) system.
# Approach: Use getattr() in dispatch() to dynamically route HTTP methods
#   (GET, POST, etc.) to corresponding lowercase handler methods on the view.
#   as_view() returns a closure that instantiates the class and calls dispatch,
#   mimicking Django's pattern of one view instance per request.
# Time complexity: O(n) for DetailView lookup, O(1) for others.
# Space complexity: O(1) auxiliary space.
# Key steps:
#   1. Request/Response are simple data containers.
#   2. View.dispatch() lowercases the method, uses getattr to find the handler.
#   3. View.as_view() returns a closure wrapping instantiation + dispatch.
#   4. ListView.get() returns all items.
#   5. CreateView.post() validates required_fields, then appends to items.
#   6. DetailView.get() searches items by lookup_field from query_params.


class Request:
    def __init__(self, method: str, data: dict = None, query_params: dict = None):
        self.method = method
        self.data = data or {}
        self.query_params = query_params or {}


class Response:
    def __init__(self, status_code: int, data=None):
        self.status_code = status_code
        self.data = data


class View:
    def dispatch(self, request: Request) -> Response:
        # Convert "GET" -> "get", then look for self.get, self.post, etc.
        handler = getattr(self, request.method.lower(), None)
        if handler is None:
            return Response(405, {"error": "Method not allowed"})
        return handler(request)

    @classmethod
    def as_view(cls):
        # Return a callable that creates a fresh instance per request
        def view_func(request: Request) -> Response:
            instance = cls()
            return instance.dispatch(request)
        return view_func


class ListView(View):
    items = []

    def get(self, request: Request) -> Response:
        return Response(200, self.items)


class CreateView(View):
    items = []
    required_fields = []

    def post(self, request: Request) -> Response:
        # Check which required fields are missing from the request data
        missing = sorted(f for f in self.required_fields if f not in request.data)
        if missing:
            return Response(400, {"error": "Missing fields", "fields": missing})
        self.items.append(request.data)
        return Response(201, request.data)


class DetailView(View):
    items = []
    lookup_field = "id"

    def get(self, request: Request) -> Response:
        lookup_value = request.query_params.get(self.lookup_field)
        # Linear scan for the first item matching the lookup field
        for item in self.items:
            if item.get(self.lookup_field) == lookup_value:
                return Response(200, item)
        return Response(404, {"error": "Not found"})
